  1→import { Injectable, Logger } from '@nestjs/common';
  2→import { OpenAI } from 'openai';
  3→
  4→import { getEnv } from '@utils/get-env-variable.util';
  5→
  6→import { OPENAI_API_KEY } from '@constants/env-variables.constant';
  7→
  8→import { MMSStyleToProcess } from '@interfaces/mms-style-to-process.interface';
  9→
 10→import { LogExecution } from '@decorators/log-execution.decorator';
 11→
 12→export interface ProductFeatureResponse {
 13→	description?: string[];
 14→	error?: string;
 15→}
 16→
 17→export interface EmbeddingTextResponse {
 18→	text: string;
 19→}
 20→
 21→export interface ProductEmbeddingInput {
 22→	name: string;
 23→	product_type: string | null;
 24→	style_type: string | null;
 25→	primary_category_name: string | null;
 26→	sub_category_names: string[] | null;
 27→	broad_category_names: string[] | null;
 28→	features: string | null;
 29→	general_comments: string | null;
 30→	decoration_method: string | null;
 31→	manufacturer: string | null;
 32→	brand: string[] | null;
 33→	condensed_features: string[] | null;
 34→	sizes: string[] | null;
 35→}
 36→
 37→@Injectable()
 38→export class OpenAIService {
 39→	private readonly logger = new Logger(OpenAIService.name);
 40→	private readonly openai: OpenAI;
 41→
 42→	constructor() {
 43→		const apiKey = getEnv<string>({ key: OPENAI_API_KEY });
 44→		this.openai = new OpenAI({ apiKey, baseURL: 'https://api.openai.com/v1' });
 45→	}
 46→
 47→	async generateProductFeatures({
 48→		productInfo,
 49→	}: {
 50→		productInfo: MMSStyleToProcess;
 51→	}): Promise<ProductFeatureResponse> {
 52→		try {
 53→			this.logger.log(`Processing product features for id: ${productInfo.id}`);
 54→
 55→			const prompt = this.buildPrompt({ productInfo });
 56→
 57→			const response = await this.getOpenAIResponse(prompt);
 58→
 59→			this.logger.log(`Successfully generated features for id: ${productInfo.id}`);
 60→			return response;
 61→		} catch (error) {
 62→			this.logger.error(`Error processing product ${productInfo.id}:`, error);
 63→			return {
 64→				error: `Failed to process product: ${error instanceof Error ? error.message : 'Unknown error'}`,
 65→			};
 66→		}
 67→	}
 68→
 69→	@LogExecution({
 70→		paramFormatter: (params: [{ product: ProductEmbeddingInput }]) => ({
 71→			name: params[0].product.name,
 72→		}),
 73→	})
 74→	async generateEmbeddingText({
 75→		product,
 76→	}: {
 77→		product: ProductEmbeddingInput;
 78→	}): Promise<EmbeddingTextResponse> {
 79→		const productData = {
 80→			name: product.name,
 81→			product_type: product.product_type,
 82→			style_type: product.style_type,
 83→			category: product.primary_category_name,
 84→			subcategories: product.sub_category_names,
 85→			broad_categories: product.broad_category_names,
 86→			features: product.features,
 87→			description: product.general_comments,
 88→			decoration_method: product.decoration_method,
 89→			manufacturer: product.manufacturer,
 90→			brand: product.brand,
 91→			condensed_features: product.condensed_features,
 92→			sizes: product.sizes,
 93→		};
 94→
 95→		const completion = await this.openai.chat.completions.create({
 96→			messages: [
 97→				{
 98→					role: 'system',
 99→					content: `You are a senior data engineer and data analyst who is an expert in generating text embeddings for neural product search.
100→Your task: given product data, produce a single natural-language paragraph optimized for a distilroberta-v1 embedding model (512 token limit).
101→
102→Rules:
103→- Write fluent, human-readable sentences — no bullet points, no pipe delimiters, no markdown.
104→- Lead with the product name and what it is.
105→- Describe key physical features, materials, and use cases.
106→- Mention important category information (primary category, and few broad categories if they exist). as words, not as sentences.
107→- Highlight occasions, events, and audiences this product is ideal for.
108→- Include the decoration/customization method naturally (3-4 words).
109→- Mention the manufacturer/brand only once if relevant.
110→- Highlight occasions, events, and audiences this product is ideal for.
111→- Count a few (6 max) key features and details from condensed_features if available, use 3-4 words per feature, and integrate them naturally into the text.
112→- Skip null/empty fields silently — never say "unknown" or "N/A".
113→- Do NOT invent features not present in the input data.
114→- Output ONLY valid JSON: {"text": "your paragraph here"}`,
115→				},
116→				{
117→					role: 'user',
118→					content: `Generate embedding text for this product:\n${JSON.stringify(productData)}`,
119→				},
120→			],
121→			model: 'gpt-4o-mini',
122→			response_format: { type: 'json_object' },
123→			temperature: 0.3,
124→			max_tokens: 350,
125→		});
126→
127→		if (!completion.choices[0]?.message.content) {
128→			throw new Error('Empty response from OpenAI');
129→		}
130→
131→		const parsed = JSON.parse(
132→			completion.choices[0].message.content,
133→		) as EmbeddingTextResponse;
134→
135→		if (!parsed.text || typeof parsed.text !== 'string') {
136→			this.logger.error(
137→				'Invalid response format from OpenAI:',
138→				JSON.stringify(completion.choices[0].message.content),
139→			);
140→			return { text: '' };
141→		}
142→
143→		return parsed;
144→	}
145→
146→	private buildPrompt({ productInfo }: { productInfo: MMSStyleToProcess }): string {
147→		return `
148→The description should be present and be suitable for product recommendation model without mentioning names and brands.
149→Description should be an array of feature strings.
150→Response format: { "description": feature[] } in JSON format.
151→
152→Product in JSON format: ${JSON.stringify(productInfo, null, 2)}
153→`;
154→	}
155→
156→	private async getOpenAIResponse(prompt: string): Promise<ProductFeatureResponse> {
157→		const completion = await this.openai.chat.completions.create({
158→			messages: [
159→				{
160→					role: 'system',
161→					content: `You are an expert in data preprocessing and feature engineering for machine learning.
162→				Your job is prepare data for training Related Products model based on "Content-based" approach.
163→				Your need to define key features, product details and important words for products and build array of features.
164→          `,
165→				},
166→				{ role: 'user', content: [{ type: 'text', text: prompt }] },
167→			],
168→			model: 'gpt-4o-mini',
169→			response_format: { type: 'json_object' },
170→		});
171→
172→		if (!completion.choices[0]) {
173→			return { error: 'No response from OpenAI' };
174→		}
175→
176→		const content = completion.choices[0].message.content;
177→		if (!content) {
178→			return { error: 'Empty response from OpenAI' };
179→		}
180→
181→		try {
182→			const parsedResponse = JSON.parse(content) as ProductFeatureResponse;
183→
184→			const fieldNames = Object.keys(parsedResponse);
185→			const firstFieldName = fieldNames[0] as keyof ProductFeatureResponse;
186→
187→			if (!parsedResponse.description) {
188→				const fieldValue = parsedResponse[firstFieldName];
189→				return {
190→					description:
191→						typeof fieldValue === 'string'
192→							? (JSON.parse(fieldValue) as string[])
193→							: (fieldValue ?? []),
194→					...parsedResponse,
195→				};
196→			}
197→
198→			return parsedResponse;
199→		} catch (parseError) {
200→			this.logger.error('Failed to parse OpenAI response:', parseError);
201→			return { error: 'Failed to parse OpenAI response' };
202→		}
203→	}
204→}
