 26→		CM.registerAsync({
 27→			imports: [EnvConfigModule],
 28→			inject: [EnvConfigService],
 29→			useFactory: (config: EnvConfigService) => {
 30→				const namespace = `${config.get({ key: SERVER_NAME })}:${config.get({ key: NODE_ENV })}`;
 31→				const cacheWriteUrl = config.get<string>({ key: REDIS_URL });
