 40→					],
 41→				};
 42→			},
 43→		}),
 44→	],
 45→	providers: [
 46→		CacheService,
 47→		{
 48→			provide: CACHE_WRITE_MANAGER,
 49→			useFactory: (config: EnvConfigService) => {
 50→				const namespace = `${config.get({ key: SERVER_NAME })}:${config.get({ key: NODE_ENV })}`;
 51→				const cacheWriteUrl = config.get<string>({ key: REDIS_URL });
 52→				return createKeyv(cacheWriteUrl, {
 53→					namespace,
 54→					useUnlink: true,
 55→					keyPrefixSeparator: ':',
 56→				});
 57→			},
 58→			inject: [EnvConfigService],
 59→		},
 60→		{
 61→			provide: CACHE_READ_MANAGER,
 62→			useFactory: (config: EnvConfigService) => {
 63→				const namespace = `${config.get({ key: SERVER_NAME })}:${config.get({ key: NODE_ENV })}`;
 64→				const cacheReadUrl = config.get<string>({ key: REDIS_READ_URL });
