 74→			provide: REDIS_WRITE_CLIENT,
 75→			useFactory: (config: EnvConfigService) => {
 76→				const cacheUrl = config.get<string>({ key: REDIS_URL });
 77→				return new Redis(cacheUrl, {
 78→					retryStrategy: (times) => {
 79→						const delay = Math.min(times * 50, 2000);
 80→						return delay;
 81→					},
 82→					maxRetriesPerRequest: 3,
 83→					enableReadyCheck: true,
 84→					connectTimeout: 10000,
 85→					lazyConnect: false,
 86→					reconnectOnError: (err) => {
 87→						const targetError = 'READONLY';
 88→						return err.message.includes(targetError);
 89→					},
 90→				});
 91→			},
 92→			inject: [EnvConfigService],
 93→		},
 94→		{
 95→			provide: REDIS_READ_CLIENT,
 96→			useFactory: (config: EnvConfigService) => {
 97→				const cacheReadUrl = config.get<string>({ key: REDIS_READ_URL });
