101→						return delay;
102→					},
103→					maxRetriesPerRequest: 3,
104→					enableReadyCheck: true,
105→					connectTimeout: 10000,
106→					lazyConnect: false,
107→					readOnly: true,
108→				});
109→			},
110→			inject: [EnvConfigService],
111→		},
112→	],
113→	exports: [
